export function getKnownClient(appName: string): KnownClient | null {
  const normalized = appName.toLowerCase();

  for (const { keywords, client } of KNOWN_CLIENTS) {
    if (keywords.some((kw) => normalized.includes(kw))) {
      return client;
    }
  }

  return null;
}
